  <rect x="20" y="138" width="660" height="60" rx="6" fill="#2a1a11"/>
  <text x="34" y="161" fill="#fed7aa" font-family="sans-serif" font-size="15" font-weight="700">+0-20 min — Bots et snipers affluent, prix +575 %</text>
